module RefModule (
    input clk,
    input rst,
    output [3:0] q
);

    reg [3:0] unused_q_reg;

    always @(posedge clk) begin
        if (rst)
            unused_q_reg <= 4'b0000;
        else
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
